using System;
using UnityEngine;

namespace APTromboneChampMod;

public static class Base64Images
{
    private const string ICON_AP_FLAT = "";
    public static readonly Sprite ArchipelagoCollection = FromBase64(ICON_AP_FLAT, 200, 200);

    private const string ICON_AP_FILTER = "";
    public static readonly Sprite ArchipelagoCollectionFiltered = FromBase64(ICON_AP_FILTER, 200, 200);

    private const string ICON_AP_LOCKED = "";
    public static readonly Sprite ArchipelagoCollectionLocked = FromBase64(ICON_AP_LOCKED, 200, 200);

    private const string ICON_AP = "";
    public static readonly Sprite Archipelago = FromBase64(ICON_AP, 40, 40);

    private const string ICON_AP_DC = "";
    public static readonly Sprite ArchipelagoDisconnected = FromBase64(ICON_AP_DC, 40, 40);

    private static Sprite FromBase64(string b64, int width, int height)
    {
        byte[] imageBytes = Convert.FromBase64String(b64);
        Texture2D tex = new Texture2D(width, height);
        tex.LoadImage(imageBytes);
        return Sprite.Create(tex, new Rect(0f, 0f, width, height), new Vector2(0.5f, 0.5f), 100.0f);
    }
}